    /**
     * Rerank a list of documents by relevance to a query.
     *
     * Returns documents sorted descending by score. Applies {@code top_k} truncation if
     * configured.
     * {@literal @}throws KreuzbergRsException - KreuzbergError.Validation if {@code query} is empty or blank.
     * - KreuzbergError.MissingDependency if ONNX Runtime is not installed (ONNX path).
     * - KreuzbergError.Reranking if the preset is unknown or model download fails.
     *
     * Since v5.0.0.
     */
    public static List<RerankedDocument> rerank(
        final String query,
        final List<String> documents,
        final RerankerConfig config
    ) throws KreuzbergRsException {
        java.util.Objects.requireNonNull(query, "query must not be null");
        java.util.Objects.requireNonNull(documents, "documents must not be null");
        java.util.Objects.requireNonNull(config, "config must not be null");
        return KreuzbergRs.rerank(query, documents, config);
    }

    /**
     * Stub for builds without the {@code reranker} feature.
     *
     * Since v5.0.0.
     */
    public static List<RerankedDocument> rerankAsync(
        final String query,
        final List<String> documents,
        final RerankerConfig config
    ) throws KreuzbergRsException {
        java.util.Objects.requireNonNull(query, "query must not be null");
        java.util.Objects.requireNonNull(documents, "documents must not be null");
        java.util.Objects.requireNonNull(config, "config must not be null");
        return KreuzbergRs.rerankAsync(query, documents, config);
    }

